import React from 'react';
import Article from '../Article.js';
import './Head.css';
import { stories } from '../Stories.js';

var temp = stories;

function Head(props) {

  return (
    <div className='Head'>

      <Article index={props.head}/>

    </div>
  );
}

export default Head;
